"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import {
  BarChart3Icon,
  FlaskConicalIcon,
  FileTextIcon,
  MessagesSquareIcon,
} from "lucide-react";
import { cn } from "@/lib/utils";

const navItems = [
  {
    href: "/app",
    label: "Chat",
    description: "Agent Mode",
    icon: MessagesSquareIcon,
  },
  {
    href: "/app/metrics",
    label: "Metrics",
    description: "Semantic Layer",
    icon: BarChart3Icon,
  },
  {
    href: "/app/experiments",
    label: "Experiments",
    description: "A/B",
    icon: FlaskConicalIcon,
  },
  {
    href: "/app/artifacts",
    label: "Artifacts",
    description: "Team Knowledge",
    icon: FileTextIcon,
  },
];

export function SidebarNav({
  onNavigate,
}: Readonly<{
  onNavigate?: () => void;
}>) {
  const pathname = usePathname();

  return (
    <nav className="space-y-1">
      {navItems.map((item) => {
        const isActive =
          item.href === "/app"
            ? pathname === "/app" || pathname.startsWith("/app/chat")
            : pathname.startsWith(item.href);
        const Icon = item.icon;

        return (
          <Link
            key={item.href}
            href={item.href}
            onClick={onNavigate}
            className={cn(
              "flex min-h-12 items-center gap-3 rounded-[1.15rem] border px-3 py-2.5 transition-colors",
              isActive
                ? "border-primary/20 bg-primary/10 text-primary"
                : "border-transparent bg-transparent text-foreground hover:border-border/70 hover:bg-white/70",
            )}
          >
            <div
              className={cn(
                "flex size-9 shrink-0 items-center justify-center rounded-[0.95rem]",
                isActive ? "bg-primary text-primary-foreground" : "bg-secondary text-foreground",
              )}
            >
              <Icon className="size-[15px]" />
            </div>
            <div className="min-w-0">
              <p className="truncate text-sm font-semibold leading-5">{item.label}</p>
              <p className="truncate text-[11px] text-muted-foreground">{item.description}</p>
            </div>
          </Link>
        );
      })}
    </nav>
  );
}
